var geometry = new api.THREE.BoxGeometry(2.2, 0.15, 0.05);
                var material = new api.THREE.MeshPhongMaterial({ color: 0xE8593C });
                var ruler = new api.THREE.Mesh(geometry, material);
                api.group.add(ruler);
                return {
                  update: function(t) {
                    ruler.rotation.z = t * 0.015;
                    ruler.rotation.x = 0.3;
                  }
                };

var elapsed = 0;
        return {
          draw: function(ctx, W, H, t, dt) {
            ctx.fillStyle = '#F5F0E8';
            ctx.fillRect(0, 0, W, H);

            var dropInterval = 0.35;
            var holdTime = 2;
            var cycle = 12 * dropInterval + holdTime;
            elapsed += Math.min(dt || 0, 0.05);
            if (elapsed > cycle) { elapsed -= cycle; }
            var count = Math.min(Math.floor(elapsed / dropInterval), 12);

            function drawTarget(cx, cy, label) {
              ctx.strokeStyle = '#9CA3AF';
              ctx.lineWidth = 1;
              [50, 33, 16].forEach(function(r) {
                ctx.beginPath();
                ctx.arc(cx, cy, r, 0, Math.PI * 2);
                ctx.stroke();
              });
              ctx.fillStyle = '#333';
              ctx.font = '12px Arial';
              ctx.fillText(label, cx - 60, cy + 70);
            }

            var leftCx = W * 0.28, leftCy = H / 2 - 10;
            var rightCx = W * 0.72, rightCy = H / 2 - 10;
            drawTarget(leftCx, leftCy, 'Accurate & precise');
            drawTarget(rightCx, rightCy, 'Precise, not accurate');

            function seededRand(i, salt) {
              var x = Math.sin(i * 12.9898 + salt) * 43758.5453;
              return x - Math.floor(x);
            }

            ctx.fillStyle = '#DC2626';
            for (var i = 0; i < count; i++) {
              var r1 = seededRand(i, 1) * 8;
              var a1 = seededRand(i, 2) * Math.PI * 2;
              ctx.beginPath();
              ctx.arc(leftCx + Math.cos(a1) * r1, leftCy + Math.sin(a1) * r1, 3, 0, Math.PI * 2);
              ctx.fill();

              var r2 = seededRand(i, 3) * 6;
              var a2 = seededRand(i, 4) * Math.PI * 2;
              ctx.beginPath();
              ctx.arc(rightCx + 32 + Math.cos(a2) * r2, rightCy - 28 + Math.sin(a2) * r2, 3, 0, Math.PI * 2);
              ctx.fill();
            }

            ctx.fillStyle = '#333';
            ctx.font = 'bold 13px Arial';
            ctx.fillText('Same tight cluster (precision) can still miss the true value (accuracy)', 12, 25);
          }
        };

return {
          draw: function(ctx, w, h) {
            ctx.clearRect(0, 0, w, h);
            ctx.fillStyle = '#F5F0E8';
            ctx.fillRect(0, 0, w, h);

            var trueLength = 10.0;
            var tick = (state.tickSize !== undefined) ? state.tickSize : 0.1;
            var reading = Math.round(trueLength / tick) * tick;

            var barX = 40, barY = h / 2, barW = w - 80;
            ctx.strokeStyle = '#111827';
            ctx.lineWidth = 3;
            ctx.beginPath();
            ctx.moveTo(barX, barY);
            ctx.lineTo(barX + barW, barY);
            ctx.stroke();

            var numTicks = Math.min(Math.floor(trueLength / tick), 200);
            ctx.strokeStyle = '#6B7280';
            ctx.lineWidth = 1;
            for (var i = 0; i <= numTicks; i++) {
              var x = barX + (i * tick / trueLength) * barW;
              ctx.beginPath();
              ctx.moveTo(x, barY - 8);
              ctx.lineTo(x, barY + 8);
              ctx.stroke();
            }

            ctx.fillStyle = '#111827';
            ctx.font = 'bold 13px Arial';
            ctx.fillText('True length: ' + trueLength.toFixed(2) + ' m', 40, 30);
            ctx.fillText('Ruler reads (nearest ' + tick.toFixed(2) + ' m): ' + reading.toFixed(2) + ' m', 40, 52);
          },
          onControlChange: function(id, val) {
            state[id] = val;
          },
          init: function() {
            state.tickSize = 0.1;
          }
        };
